/*
   Return the largest sum of any contiguous subarray in the vector x.
   If x is empty, the function returns the lowest representable int,
   matching the original implementation's behaviour.
 */
inline int maximumSubarray(const std::vector<int>& x) {
    // If the vector is empty, no subarray exists → return the same sentinel
    if (x.empty())
        return std::numeric_limits<int>::lowest();

    int max_ending_here = 0;
    int max_so_far = std::numeric_limits<int>::lowest();

    for (const int v : x) {
        max_ending_here = std::max(v, max_ending_here + v);
        max_so_far = std::max(max_so_far, max_ending_here);
    }

    return max_so_far;
}
