```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement
{
    size_t row, column;
    double value;
};

/*
 * Computes y = alpha * A * x + beta * y
 *   A : sparse matrix in COO format (size M×N)
 *   x , y : dense vectors of length N and M respectively
 *
 * The function is thread‑safe and parallelised with OpenMP.
 */
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 size_t M, size_t N)
{
    // 1. scale y by beta – embarrassingly parallel
    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(y.size()); ++i)
        y[i] *= beta;

    // 2. accumulate A*x into y.  We protect each y[row] with an atomic
    //    because multiple elements can contribute to the same row.
    #pragma omp parallel for schedule(static)
    for (long long k = 0; k < static_cast<long long>(A.size()); ++k)
    {
        const auto &e = A[k];
        if (e.row >= M || e.column >= N)   // graceful out‑of‑bounds guard
            continue;

        double tmp = alpha * e.value * x[e.column];
        #pragma omp atomic
        y[e.row] += tmp;
    }
}
