        auto &lb = local_bins[tid];
        std::size_t stride = 1;
        for (std::size_t i = omp_get_thread_num(); i < image.size(); i += nthreads) {
            // bound check: image[i] is guaranteed to be 0-255, but guard anyway
            unsigned char val = static_cast<unsigned char>(image[i] & 0xFF);
            ++lb[val];
        }
    }

    // reduce local bins into the result
    for (int t = 0; t < nthreads; ++t) {
        const auto &lb = local_bins[t];
        for (int i = 0; i < 256; ++i) {
            bins[i] += lb[i];
        }
