/*
 Count the number of doubles in the vector `x` that have a fractional
 part in the four equal-sized intervals:
     [0,    0.25), [0.25, 0.5), [0.5, 0.75), [0.75, 1)
 and store the counts in `bins`.
 */
void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins) {
    // Reset bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Use OpenMP parallel for with a private local bins array per thread,
    // then merge results in a critical section.
    const std::size_t n = x.size();

    #pragma omp parallel
    {
        std::array<std::size_t, 4> local = {0, 0, 0, 0};

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            double val = x[i];
            // Get fractional part without using std::modf for speed.
            double frac = val - std::floor(val);
            if (frac < 0.25)
                local[0] += 1;
            else if (frac < 0.5)
                local[1] += 1;
            else if (frac < 0.75)
                local[2] += 1;
            else
                local[3] += 1;
        }

        // Merge local counts into global bins
        #pragma omp critical
        {
            bins[0] += local[0];
            bins[1] += local[1];
            bins[2] += local[2];
            bins[3] += local[3];
        }
    }
}
