/* Count the number of cartesian points in each quadrant.
   The vector points contains a list of `Point` objects.
   Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9}, {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins) {
    // initialise output
    bins.fill(0);

    // Thread‑local accumulators
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<size_t, 4>> local_bins(n_threads);
    for (auto& lb : local_bins) lb.fill(0);

