        const int tid = omp_get_thread_num();
        const auto& p = points[i];
        if (p.x >= 0.0) {
            if (p.y >= 0.0)
                local_bins[tid][0]++;          // Q1
            else
                local_bins[tid][3]++;          // Q4
        } else {
            if (p.y >= 0.0)
                local_bins[tid][1]++;          // Q2
            else
                local_bins[tid][2]++;          // Q3
        }
    }

    // Reduce all thread–local bins into the result
    for (int t = 0; t < n_threads; ++t)
        for (size_t q = 0; q < 4; ++q)
            bins[q] += local_bins[t][q];
}
