#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <cstdint>
#include <limits>
#include <omp.h>

/* Compute the highest node degree in the undirected graph. The graph is defined
   in the adjacency matrix A. A is an NxN adjacency matrix stored in row-major.
   The function keeps the exact semantics of the original implementation.
 */
inline int maxDegree(std::vector<int> const& A, size_t N) noexcept {
    // Fast path for small matrices – a single thread is sufficient
    if (N <= 64) {
        int highest = 0;
        const int* restrict row = A.data();
        for (size_t i = 0; i < N; ++i) {
            int deg = 0;
            const int* restrict ptr = row + i * N;
            for (size_t j = 0; j < N; ++j) {
                deg += ptr[j];
            }
            if (deg > highest) highest = deg;
        }
        return highest;
    }

    int globalMax = 0;

    // Parallel reduction – each thread computes a local maximum
    #pragma omp parallel
    {
        int localMax = 0;
        const int* restrict data = A.data();
        #pragma omp for schedule(static)
        for (int i = 0; i < static_cast<int>(N); ++i) {
            int deg = 0;
            const int* restrict row = data + i * N;
            // Unroll the inner loop to reduce loop overhead
            size_t j = 0, n = N;
            constexpr size_t UNROLL = 8;
            for (; j + UNROLL - 1 < n; j += UNROLL) {
                deg += row[j]     + row[j+1]   + row[j+2]   + row[j+3]   +
                       row[j+4]   + row[j+5]   + row[j+6]   + row[j+7];
            }
            for (; j < n; ++j) deg += row[j];
            if (deg > localMax) localMax = deg;
        }
        // Thread‑safe reduction to the global maximum
        #pragma omp critical
        if (localMax > globalMax) globalMax = localMax;
    }
    return globalMax;
}
