#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*  Optimised sparse matrix-matrix multiplication.
    A : MxK sparse matrix in COO format.
    X : KxN sparse matrix in COO format.
    Y : resulting dense MxN matrix in row‑major order.
*/
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          std::size_t M,
          std::size_t K,
          std::size_t N)
{
    /* Initialise dense result */
    Y.assign(M * N, 0.0);

    /* Build index: for each row of X store all non‑zeros. */
    std::vector<std::vector<COOElement>> x_by_row(K);
    for (const auto& x : X)
        x_by_row[x.row].push_back(x);

    /* Parallel outer loop over A. Each iteration independently writes
       into distinct rows of Y, but multiple threads may write to the
       same Y entry when different A elements share a row.  The
       addition is associative for doubles, so atomic updates are
       sufficient. */
    #pragma omp parallel for schedule(dynamic, 64)
    for (std::size_t ai = 0; ai < A.size(); ++ai)
    {
        const auto& a = A[ai];
        if (a.column >= x_by_row.size()) continue;   // safety

        const auto& x_vec = x_by_row[a.column];
        for (const auto& x : x_vec)
        {
            std::size_t idx = a.row * N + x.column;
            double prod = a.value * x.value;
            #pragma omp atomic
            Y[idx] += prod;
        }
    }
}
