#pragma once
#include <vector>
#include <algorithm>

int largestComponent(std::vector<int> const& A, size_t N) {
    if (N == 0) return 0;

    // Union‑Find data structure
    std::vector<int> parent(N);
    std::vector<int> sz(N, 1);
    for (int i = 0; i < N; ++i) parent[i] = i;

    auto find = [&](int x) {
        int root = x;
        while (parent[root] != root) root = parent[root];
        // path compression
        while (parent[x] != root) {
            int nxt = parent[x];
            parent[x] = root;
            x = nxt;
        }
        return root;
    };

    auto unite = [&](int a, int b) {
        int ra = find(a), rb = find(b);
        if (ra == rb) return;
        if (sz[ra] < sz[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        sz[ra] += sz[rb];
    };

    // Build edges (undirected graph)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int* row = &A[i * N];
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            if (row[j] == 1) unite(i, j);
        }
    }

    // Find largest component size
    int maxSize = 0;
    for (int i = 0; i < static_cast<int>(N); ++i) {
        if (parent[i] == i) { // root
            if (sz[i] > maxSize) maxSize = sz[i];
        }
    }
    return maxSize;
}
