    int num_threads = omp_get_max_threads();

    // 1. Compute partial sums (each thread gets a contiguous chunk)
    std::vector<int64_t> partialSum(num_threads);
    std::vector<int64_t> prefixChunk(n);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        // Determine chunk boundaries
        size_t start = (n * tid) / num_threads;
        size_t end   = (n * (tid + 1)) / num_threads;
        if (start >= end) return;   // no work for this thread

        int64_t sum = 0;
        for (size_t i = start; i < end; ++i) {
            sum += x[i];
            prefixChunk[i] = sum;
        }
        partialSum[tid] = sum;
    }

    // 2. Compute offsets from partial sums (serial part, very small)
    std::vector<int64_t> offset(num_threads, 0);
    for (int i = 1; i < num_threads; ++i) {
        offset[i] = offset[i - 1] + partialSum[i - 1];
    }

    // 3. Add offsets to each chunk (parallel)
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        if (tid >= num_threads) return;
        size_t start = (n * tid) / num_threads;
        size_t end   = (n * (tid + 1)) / num_threads;
        if (start >= end) return;

        int64_t add = offset[tid];
        for (size_t i = start; i < end; ++i) {
            prefixChunk[i] += add;
        }
    }

    // 4. Sum all prefix sums (parallel reduction)
    int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
    for (size_t i = 0; i < n; ++i) {
        total += prefixChunk[i];
    }

    return total;
}
