/* Compute the inclusive prefix sum of x into output.
 * The function keeps the exact semantics of std::inclusive_scan but
 * is parallelized on systems with sufficient cores.
 */
inline void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t>& output)
{
    const std::size_t n = x.size();

    /* Work only if the vector is non‑empty */
    if (n == 0) return;

    output.resize(n);

    /* Parallel block size tuned to the cache line width (~64 bytes)
     * We accumulate sums per thread and then perform a prefix on the
     * per‑thread results. */
    constexpr std::size_t BLOCK = 4096;                     // 4 KiB blocks
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int nthreads = omp_get_num_threads();

        /* Determine the range this thread has to process */
        std::size_t start = (n * tid) / nthreads;
        std::size_t end   = (n * (tid + 1)) / nthreads;

        /* Local exclusive sum for this thread */
        int64_t local_sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            output[i] = x[i] + local_sum;
            local_sum = output[i];
        }

        /* Share the final local sum with other threads using
         * omp critical or atomic.  The array ``thread_sums`` holds
         * the exclusive sum produced by each thread */
        static std::vector<int64_t> thread_sums;
#pragma omp single
        {
            thread_sums.resize(nthreads, 0);
        }

        thread_sums[tid] = local_sum;

#pragma omp barrier   // all threads finished local passes

        /* Calculate an offset for this thread from the sums of
         * all preceding threads. */
        int64_t offset = 0;
        for (int t = 0; t < tid; ++t) offset += thread_sums[t];

        /* Add the offset to all locally computed values */
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
