/* Compute one iteration of a 3-point 1D Jacobi stencil on `input`.
   Each element of `input` will be averaged with its two neighbors
   and stored in the corresponding element of `output`.  Read past
   the boundaries as 0.0.  The function is fully parallelized with
   OpenMP and avoids unnecessary bounds tests. */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    const std::size_t n = input.size();
    const double inv3 = 1.0 / 3.0;

    // Parallel loop, safe because each iteration writes to a unique
    // output element.  No dependencies exist.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        const double left  = (i > 0)      ? input[i - 1] : 0.0;
        const double right = (i + 1 < static_cast<std::ptrdiff_t>(n))
                               ? input[i + 1] : 0.0;
        const double val   = left + input[i] + right;
        output[i] = val * inv3;
    }
}
