/* Return the length of the shortest path from source to dest in the undirected graph defined by
   the adjacency matrix A (row‑major). Assumes the graph is connected. */
inline int shortestPathLength(const std::vector<int>& A, size_t N,
                              int source, int dest) {
    if (source == dest) return 0;
    std::vector<char> visited(N, 0);
    std::vector<int> q(N);          // queue using ring buffer
    std::vector<int> dist(N, -1);

    size_t head = 0, tail = 0;
    visited[source] = 1;
    dist[source] = 0;
    q[tail++] = source;

    while (head < tail) {
        int cur = q[head++];
        int curDist = dist[cur];
        if (cur == dest) return curDist;

        size_t base = static_cast<size_t>(cur) * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                dist[i] = curDist + 1;
                q[tail++] = static_cast<int>(i);
            }
        }
    }
    return std::numeric_limits<int>::max();
}
