/*
 * Compute the discrete Fourier transform (DFT) of a real input vector `x`.
 * The computed complex spectrum is stored in `output`. The size of
 * `output` will be exactly `x.size()`.  The implementation is
 * numerically stable and mathematically equivalent to the reference
 * DFT definition, yet heavily optimised for speed on a modern x86‑64
 * machine with OpenMP support.
 *
 * Parameters
 * ----------
 * x       : const reference to the input vector (real values).
 * output  : reference to the vector where the complex DFT coefficients
 *           will be written.
 */
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    /* Parallelise outer loop over frequency bins.
     * Each iteration is completely independent.
     */
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k)
    {
        const double angle           = -2.0 * M_PI * static_cast<double>(k) / static_cast<double>(N);
        const std::complex<double> w = std::polar(1.0, angle);   // e^{-j 2πk/N}
        std::complex<double> term(1.0, 0.0);                     // Current twiddle factor

        std::complex<double> sum(0.0, 0.0);
        for (std::size_t n = 0; n < N; ++n)
        {
            sum += x[n] * term;
            term *= w;        // advance twiddle factor: e^{-j 2πk/N} * current
        }
        output[k] = sum;
    }
}
