```cpp
#pragma once
#include <vector>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Factorize the sparse matrix A (in COO format) into A = L * U
 * where L is lower triangular (unit diagonal) and U is upper triangular.
 * L and U are returned as flat row‑major arrays of size N * N.
 *
 * The implementation avoids any dynamic allocation inside the inner
 * loops, uses contiguous memory for L, U and the dense form of A,
 * and relies on pointer arithmetic for maximum performance.
 */
void luFactorize(const std::vector<COOElement>& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 std::size_t N)
{
    // Resize output matrices
    L.resize(N * N, 0.0);
    U.resize(N * N, 0.0);

    // Build dense matrix A
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A) {
        fullA[e.row * N + e.column] = e.value;
    }

    // Perform Doolittle LU decomposition
    for (std::size_t i = 0; i < N; ++i) {
        const double* fullA_i  = &fullA[i * N];
        double*       U_i      = &U[i * N];
        double*       L_i      = &L[i * N];

        // Upper part (including diagonal)
        for (std::size_t j = i; j < N; ++j) {
            double sum = fullA_i[j];
            for (std::size_t k = 0; k < i; ++k) {
                sum -= L_i[k] * U[k * N + j];
            }
            U_i[j] = sum;
        }

        // Lower part
        for (std::size_t j = 0; j < i; ++j) {
            double sum = fullA_i[j];
            for (std::size_t k = 0; k < j; ++k) {
                sum -= L_i[k] * U[k * N + j];
            }
            L_i[j] = sum / U[j * N + j];
        }

        // Diagonal of L is 1
        L_i[i] = 1.0;
    }
}
