 * (O(n)).  The behavior is identical to the original quadratic
 * implementation but with far superior performance for large inputs.
 */
double closestPair(std::vector<double> const& x) {
    const std::size_t n = x.size();
    if (n < 2) {
        return 0.0;
    }

    // Make a copy and sort it; sorting is the bottleneck
    std::vector<double> sorted(x);
    std::sort(sorted.begin(), sorted.end());

    // Scan in parallel: work is independent per pair of adjacent elements
    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel for reduction(min:minDist) schedule(static)
    for (std::size_t i = 0; i + 1 < n; ++i) {
        double d = sorted[i + 1] - sorted[i]; // sorted, so non‑negative
        if (d < minDist) {
            minDist = d;
        }
    }

    return minDist;
}
