/*
 * Compute the reverse prefix sum of the vector `x` into `output`.
 *
 * The algorithm works in a single linear pass, building the result from
 * the back of the array.  No temporary reverse copy is allocated, thus
 * it uses O(1) extra space apart from the output vector.
 *
 * Examples:
 *   input:  [1, 7, 4, 6, 6, 2]
 *   output: [2, 8, 14, 18, 25, 26]
 *
 *   input:  [3, 3, 7, 1, -2]
 *   output: [-2, -1, 6, 9, 12]
 */
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output)
{
    const std::size_t n = x.size();
    if (n == 0) {
        output.clear();
        return;
    }

    output.resize(n);

    int sum = 0;
    /* Traverse from the end toward the beginning so we can accumulate
       the inclusive sums on the fly. */
    for (std::size_t i = 0; i < n; ++i) {
        sum += x[n - 1 - i];
        output[n - 1 - i] = sum;
    }
}
