// Fast iterative radix‑2 FFT (in‑place, decimation‑in‑time)
// Utilizes cache‑friendly butterfly ordering and OpenMP parallelism.
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output) {
    // Ensure power‑of‑two size (the harness guarantees this)
    const std::size_t N = x.size();
    output = x;                         // Work on a copy
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // Pre‑compute twiddle factors
    std::vector<std::complex<double>> twiddles(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i) {
        double ang = -2.0 * M_PI * static_cast<double>(i) / static_cast<double>(N);
        twiddles[i] = std::complex<double>(std::cos(ang), std::sin(ang));
    }

    // Bit‑reversal permutation
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (i < rev) std::swap(output[i], output[rev]);

        std::size_t mask = N >> 1;
        while (rev & mask) { rev ^= mask; mask >>= 1; }
        rev ^= mask;
    }

    // Main FFT loop
    for (std::size_t s = 1; s <= logN; ++s) {
        std::size_t m = 1ULL << s;
        std::size_t m2 = m >> 1;
        std::size_t stride = N / m;

#pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < m2; ++j) {
            std::complex<double> w = twiddles[j * stride];
            for (std::size_t k = j; k < N; k += m) {
                std::size_t idx = k + m2;
                std::complex<double> t = w * output[idx];
                output[idx] = output[k] - t;
                output[k] += t;
            }
        }
    }
}
