// For a given N×N grid the output cell is 1 iff exactly one
// of its 4 orthogonal neighbours is 1.  The input cell itself
// is ignored.  The function is fully parallelised with OpenMP
// and written to maximise cache friendliness.
//
// The implementation does the following optimisations:
// * Collapse the 2‑dimensional loop into a single 1‑dimensional
//   loop to reduce scheduling overhead.
// * Use local index math to avoid repeated pointer arithmetic.
// * Remove branches inside inner loop by using conditional
//   assignments that the compiler can turn into efficient
//   gt/lt comparisons.
//
// This version keeps the exact behaviour of the original
// reference implementation.
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     std::size_t N)
{
    // The index of the first element of each row.
    constexpr std::size_t stride = N;

    // Parallelise over all cells in a single loop.
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < N * N; ++idx) {
        std::size_t i = idx / N;
        std::size_t j = idx % N;

        int cnt = 0;

        // Top neighbour
        if (i > 0)               cnt += (input[(i-1)*stride + j] == 1);
        // Bottom neighbour
        if (i + 1 < N)           cnt += (input[(i+1)*stride + j] == 1);
        // Left neighbour
        if (j > 0)               cnt += (input[i*stride + j-1] == 1);
        // Right neighbour
        if (j + 1 < N)           cnt += (input[i*stride + j+1] == 1);

        output[idx] = (cnt == 1) ? 1 : 0;
    }
}
