#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/*
 * Solve the sparse linear system Ax=b for x.
 * A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
 */
void solveLinearSystem(const std::vector<COOElement>& A,
                       const std::vector<double>& b,
                       std::vector<double>& x,
                       size_t N)
{
    // Use a 1‑D array for the dense matrix to improve cache locality
    std::vector<double> matrix(N * N, 0.0);
    std::vector<double> rhs = b;

    // Fill the matrix (parallelised to speed up when A is large)
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    x.assign(N, 0.0);          // initialise solution vector

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* 1 – Find pivot row */
        size_t maxRow = i;
        double maxVal = std::abs(matrix[i * N + i]);

        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        if (maxRow != i) {
            // Swap rows in matrix
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[maxRow * N + k], matrix[i * N + k]);
            }
            // Swap RHS
            std::swap(rhs[maxRow], rhs[i]);
        }

        /* 2 – Eliminate rows below */
        const double piv = matrix[i * N + i];
        // Avoid division by zero – the original code does not check this
        // but we keep behaviour identical by assuming matrix is nonsingular.
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -matrix[k * N + i] / piv;
            for (size_t j = i; j < N; ++j) {
                if (i == j)
                    matrix[k * N + j] = 0.0;
                else
                    matrix[k * N + j] += factor * matrix[i * N + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* Back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = rhs[i] / matrix[i * N + i];
        for (int k = i - 1; k >= 0; --k) {
            rhs[k] -= matrix[k * N + i] * x[i];
        }
    }
}
