#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct Point {
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull)
{
    const std::size_t n = points.size();
    if (n < 3) {               // convex hull is the same as the input
        hull = points;
        return;
    }

    // Sort points lexicographically by x, then y
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point &a, const Point &b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Pre‑allocate the maximum possible hull size
    std::vector<Point> tmp(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(tmp[k-2], tmp[k-1], sorted[i]) <= 0)
            --k;
        tmp[k++] = sorted[i];
    }

    // Build upper hull
    for (std::size_t i = n; i-- > 0; ) {
        while (k >= 2 && cross(tmp[k-2], tmp[k-1], sorted[i]) <= 0)
            --k;
        tmp[k++] = sorted[i];
    }

    // Remove the duplicate last point
    if (k > 1) --k;
    tmp.resize(k);
    hull = std::move(tmp);
}
