    #pragma omp parallel
    {
        std::vector<int> stack;
        stack.reserve(N);
        int localCount = 0;

        #pragma omp for schedule(dynamic, 64)
        for (int start = 0; start < static_cast<int>(N); ++start)
        {
            // Fast atomic "mark as visited" with compare_exchange.
            char expected = 0;
            if (!__atomic_compare_exchange_n(&visited[start], &expected, 1,
                                             false, __ATOMIC_RELAXED,
                                             __ATOMIC_RELAXED))
                continue;                   // already visited by another thread

            // Depth‑first search using the local stack.
            stack.clear();
            stack.push_back(start);
            while (!stack.empty())
            {
                int u = stack.back();
                stack.pop_back();

                const int* row = A.data() + u * N;
                for (int v = 0; v < static_cast<int>(N); ++v)
                {
                    if (row[v] == 1 && !visited[v])
                    {
                        char exp = 0;
                        if (__atomic_compare_exchange_n(&visited[v], &exp, 1,
                                                         false, __ATOMIC_RELAXED,
                                                         __ATOMIC_RELAXED))
                        {
                            stack.push_back(v);
                        }
                    }
                }
            }

            ++localCount;
        }

        #pragma omp atomic
        totalComponents += localCount;
    }

    return totalComponents;
}
