/*
 * 2‑D Jacobi stencil – fast version
 * ---------------------------------
 *
 *    output[i][j] = ( input[i][j]
 *                    + input[i-1][j] if i>0
 *                    + input[i+1][j] if i<N-1
 *                    + input[i][j-1] if j>0
 *                    + input[i][j+1] if j<N-1 )
 *                    / 5
 *
 * The routine is fully parallelised with OpenMP, uses a small
 * blocking loop for better cache utilisation and relies on
 * pointer arithmetic to minimise index calculations.
 */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     size_t N)
{
    const double *in   = input.data();
    double       *out  = output.data();

    /* Small block size that fits comfortably into L1 cache
       (3 * 64 bytes * 16 = 3072 bytes, i.e. 16 rows). */
    constexpr size_t B = 16;

    /* Parallel loop over all blocks. */
#pragma omp parallel for collapse(1) schedule(static)
    for (size_t bi = 0; bi < N; bi += B) {
        const size_t i_max = (bi + B < N) ? bi + B : N;
        for (size_t i = bi; i < i_max; ++i) {
            const size_t i_base = i * N;
            const size_t im1 = (i > 0)   ? (i - 1) * N : 0;
            const size_t ip1 = (i < N-1) ? (i + 1) * N : 0;
            for (size_t j = 0; j < N; ++j) {
                double sum = in[i_base + j];
                if (i > 0)   sum += in[im1 + j];
                if (i < N-1) sum += in[ip1 + j];
                if (j > 0)   sum += in[i_base + j - 1];
                if (j < N-1) sum += in[i_base + j + 1];
                out[i_base + j] = sum / 5.0;
            }
        }
    }
}
