/* Find the k‑th smallest element of the vector x.
   Example:

   input: x=[1, 7, 6, 0, 2, 2, 10, 6], k=4
   output: 6
*/
int findKthSmallest(const std::vector<int>& x, int k) {
    // Validate k
    if (k < 1 || k > static_cast<int>(x.size())) {
        throw std::out_of_range("k is out of bounds");
    }

    // Make a copy since std::nth_element modifies the container
    std::vector<int> copy = x;

    // nth_element places the element that would be at position k-1
    // in the sorted array at that index, with all smaller elements
    // before it and all larger elements after it.
    std::nth_element(copy.begin(), copy.begin() + (k - 1), copy.end());

    // The element at position k-1 is the k‑th smallest.
    return copy[k - 1];
}
