/* Compute z = alpha * x + y where x and y are sparse vectors.
 * Indices within each input vector are assumed to be strictly increasing
 * (i.e., no duplicate indices inside a single vector).  The result
 * vector z is updated in-place and must be sized large enough to
 * contain all indices from the inputs.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    const Element *xp = x.data();
    const Element *yp = y.data();
    std::size_t xs = x.size(), ys = y.size();
    std::size_t xi = 0, yi = 0;

    /* Main merge loop – one pass over the two sorted lists. */
    while (xi < xs && yi < ys)
    {
        const std::size_t ix = xp[xi].index;
        const std::size_t iy = yp[yi].index;

        if (ix < iy)            /* only x has this index */
        {
            z[ix] += alpha * xp[xi].value;
            ++xi;
        }
        else if (ix > iy)        /* only y has this index */
        {
            z[iy] += yp[yi].value;
            ++yi;
        }
        else                    /* both vectors have this index */
        {
            z[ix] += alpha * xp[xi].value + yp[yi].value;
            ++xi;
            ++yi;
        }
    }

    /* Remaining elements of x (if any). */
    #pragma omp parallel for schedule(static) if(xs - xi > 1000)
    for (std::size_t i = xi; i < xs; ++i) {
        const std::size_t idx = xp[i].index;
        z[idx] += alpha * xp[i].value;
    }

    /* Remaining elements of y (if any). */
    #pragma omp parallel for schedule(static) if(ys - yi > 1000)
    for (std::size_t i = yi; i < ys; ++i) {
        const std::size_t idx = yp[i].index;
        z[idx] += yp[i].value;
    }
}
