#include <omp.h>

struct Result {
    int startTime, duration;
    float value;
};

/* Parallel quicksort implementation
   Uses OpenMP tasks for recursive partitioning.
   Threshold 32 elements processed serially to reduce overhead.
*/
static constexpr int PARALLEL_THRESHOLD = 32;

static void quicksort_parallel(std::vector<Result> &a, int left, int right) {
    if (left >= right) return;

    /* Use median-of-three to choose pivot */
    int mid = left + (right - left) / 2;
    Result pivot = a[mid];
    std::swap(a[mid], a[right]);

    int i = left;
    for (int j = left; j < right; ++j) {
        if (a[j].startTime < pivot.startTime) {
            std::swap(a[i++], a[j]);
        }
    }
    std::swap(a[i], a[right]);

    if (i - left > PARALLEL_THRESHOLD && right - i > PARALLEL_THRESHOLD) {
        #pragma omp task shared(a)
        quicksort_parallel(a, left, i - 1);
        #pragma omp task shared(a)
        quicksort_parallel(a, i + 1, right);
    } else {
        quicksort_parallel(a, left, i - 1);
        quicksort_parallel(a, i + 1, right);
    }
}

void sortByStartTime(std::vector<Result> &results) {
    if (results.empty()) return;
    #pragma omp parallel
    {
        #pragma omp single
        {
            quicksort_parallel(results, 0, static_cast<int>(results.size()) - 1);
        }
    }
}
