struct Point {
    double x, y;
};

// Fast distance using direct arithmetic, no pow()
inline double dist(double x1, double y1, double x2, double y2) noexcept {
    double dx = x2 - x1;
    double dy = y2 - y1;
    return std::sqrt(dx * dx + dy * dy);
}

// Fast cross product
inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   Example:
   input: [{0, 3}, {1, 1}, {2, 2}, {4, 4}, {0, 0}, {1, 2}, {3, 1}, {3, 3}]
   output: 13.4477
*/
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort points – use pointer array to minimize copies
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Upper bound for hull size is 2*n
    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Build lower hull
    for (const auto& p : pts) {
        while (hull.size() >= 2 && cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Build upper hull
    const std::size_t lower_size = hull.size();
    for (std::size_t i = pts.size() - 1; i-- > 0; ) {
        const auto& p = pts[i];
        while (hull.size() > lower_size + 1 && cross(hull[hull.size() - 2], hull.back(), p) <= 0.0)
            hull.pop_back();
        hull.push_back(p);
    }

    // Remove the duplicate last point
    hull.pop_back();

    // Compute perimeter
    double perim = 0.0;
    const std::size_t m = hull.size();
    for (std::size_t i = 0; i < m; ++i) {
        const std::size_t j = (i + 1) % m;
        perim += dist(hull[i].x, hull[i].y, hull[j].x, hull[j].y);
    }
    return perim;
}
