#pragma once
#include <vector>
#include <omp.h>
#include <cstddef>
#include <cstring>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              std::size_t N)
{
    // Work copy of A and b
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    const double * restrict a = A_copy.data();
    double       * restrict ap = A_copy.data();   // mutable copy
    double       * restrict bp = b_copy.data();

    // Gaussian elimination with OpenMP parallelization
    for (std::size_t i = 0; i < N - 1; ++i)
    {
        double pivot = ap[i * N + i];
        if (pivot == 0.0) return;                 // singular matrix

        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j)
        {
            double factor = ap[j * N + i] / pivot;
            std::size_t rowBase = j * N;
            std::size_t pivotRowBase = i * N;
            // Unroll simple inner loop with pointer arithmetic
            for (std::size_t k = i; k < N; ++k)
                ap[rowBase + k] -= factor * ap[pivotRowBase + k];
            bp[j] -= factor * bp[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        double *row = ap + i * N;
        for (std::size_t j = i + 1; j < N; ++j)
            sum += row[j] * x[j];
        x[i] = (bp[i] - sum) / row[i];
    }
}
