#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <limits>

struct Point {
    double x, y;
};

static inline double dist2(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* Return the Euclidean distance between the closest two points in the vector.
 * Uses an O(n log n) divide‑and‑conquer algorithm. */
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    /* Sort points by x coordinate (stable sort for correctness). */
    std::vector<Point> px(points);
    std::sort(px.begin(), px.end(), [](const Point& a, const Point& b) {
        return a.x < b.x;
    });

    /* Auxiliary buffer for merging steps. */
    std::vector<Point> py(n);

    /* Recursive lambda: returns minimal squared distance in interval [l, r). */
    std::function<double(size_t, size_t)> rec = [&](size_t l, size_t r) -> double {
        size_t len = r - l;
        if (len <= 3) {
            double best = std::numeric_limits<double>::infinity();
            for (size_t i = l; i < r; ++i) {
                for (size_t j = i + 1; j < r; ++j) {
                    best = std::min(best, dist2(px[i], px[j]));
                }
            }
            /* Sort these few points by y for upper levels. */
            std::sort(px.begin() + l, px.begin() + r,
                      [](const Point& a, const Point& b) { return a.y < b.y; });
            return best;
        }

        size_t mid = l + len / 2;
        double midx = px[mid].x;

        double dl = rec(l, mid);
        double dr = rec(mid, r);
        double d = std::min(dl, dr);

        /* Merge the two halves sorted by y. */
        std::merge(px.begin() + l, px.begin() + mid,
                   px.begin() + mid, px.begin() + r,
                   py.begin(), [](const Point& a, const Point& b) {
                       return a.y < b.y;
                   });
        std::copy(py.begin(), py.begin() + len, px.begin() + l);

        /* Build strip of points within sqrt(d) of mid line. */
        std::vector<Point> strip;
        double distLimit = std::sqrt(d);
        for (const auto& pt : px) {
            if (pt.x - midx <= distLimit) {
                strip.push_back(pt);
            }
        }

        /* Check only next 7 points in strip (property of plane). */
        size_t sz = strip.size();
        for (size_t i = 0; i < sz; ++i) {
            for (size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < distLimit; ++j) {
                d = std::min(d, dist2(strip[i], strip[j]));
                distLimit = std::sqrt(d); // update limit if tightened
            }
        }

        return d;
    };

    double minDistSq = rec(0, n);
    return std::sqrt(minDistSq);
}
