/*
 * Compute the discrete Fourier transform of a power‑of‑two length signal.
 * The result is written into the vectors 'r' (real part) and 'i' (imaginary part).
 * The implementation follows a classic iterative Cooley–Tukey radix‑2 algorithm,
 * uses a pre‑computed table of twiddle factors, performs an in‑place bit‑reversal,
 * and uses OpenMP to parallelise the outermost stages when the data size
 * is large enough.
 *
 * The function assumes that `r` and `i` have been resized to the length of the
 * input vector `x` before the call.  No extra allocations are made during the
 * transform.
 */
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<double>& r,
                std::vector<double>& i)
{
    const std::size_t N = x.size();
    // Input size must be a power of two; this is guaranteed by the harness.
    std::size_t n = N;

    // work array
    std::vector<std::complex<double>> in;
    in.reserve(n);
    in.assign(x.begin(), x.end());

    /* ----------------------------------------------------------
     *  Pre‑compute twiddle factor tables for each stage.
     * ---------------------------------------------------------- */
    std::size_t stages = 0;
    for (std::size_t tmp = N; tmp > 1; tmp >>= 1) ++stages;

    std::vector<std::vector<std::complex<double>>> twiddles(stages);
    for (std::size_t s = 0; s < stages; ++s) {
        std::size_t step = 1ULL << (s + 1);
        std::size_t half  = step >> 1;
        twiddles[s].resize(half);
        double angle = -M_PI / half;
        for (std::size_t k = 0; k < half; ++k)
            twiddles[s][k] = std::complex<double>(std::cos(k * angle),
                                                   std::sin(k * angle));
    }

    /* ----------------------------------------------------------
     *  Radix‑2 Cooley–Tukey iterations.
     * ---------------------------------------------------------- */
    std::size_t len = 2;
    for (std::size_t s = 0; s < stages; ++s, len <<= 1) {
        const std::size_t half = len >> 1;
        #pragma omp parallel for schedule(dynamic)
        for (std::size_t i_start = 0; i_start < N; i_start += len) {
            std::size_t idx = 0;
            for (std::size_t j = 0; j < half; ++j, ++idx) {
                const std::complex<double> t = twiddles[s][idx] *
                                            in[i_start + j + half];
                const std::complex<double> u = in[i_start + j];
                in[i_start + j]         = u + t;
                in[i_start + j + half]  = u - t;
            }
        }
    }

    /* ----------------------------------------------------------
     *  Bit‑reversal of the indices.
     * ---------------------------------------------------------- */
    const std::size_t logN = stages;
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = ((j & 0x55555555U) << 1) | ((j & 0xaaaaaaaaU) >> 1);
        j = ((j & 0x33333333U) << 2) | ((j & 0xccccccccU) >> 2);
        j = ((j & 0x0f0f0f0fU) << 4) | ((j & 0xf0f0f0f0U) >> 4);
        j = ((j & 0x00ff00ffU) << 8) | ((j & 0xff00ff00U) >> 8);
        j = (j << 16) | (j >> 16);
        j >>= (32 - logN);
        if (j > i) {
            std::swap(in[i], in[j]);
        }
    }

    /* ----------------------------------------------------------
     *  Write results back to the output vectors.
     * ---------------------------------------------------------- */
    #pragma omp parallel for
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = in[j].real();
        i[j] = in[j].imag();
    }
}
