#pragma once
#include <vector>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
inline bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val)
{
    bool foundX = false, foundY = false;

    // Find val in x
    for (size_t i = 0; i < x.size(); ++i)
    {
        if (x[i] == val)
        {
            foundX = true;
            // If we already know it's in y, we can return false immediately
            if (foundY) return false;
        }
    }

    // Find val in y
    for (size_t i = 0; i < y.size(); ++i)
    {
        if (y[i] == val)
        {
            foundY = true;
            if (foundX) return false;
        }
    }

    // XOR of the two booleans
    return foundX ^ foundY;
}
