inline size_t findClosestToPi(const std::vector<double>& x) {
    // Handle empty vector (undefined in original, but guard against crash)
    if (x.empty()) return 0;

    const double pi  = M_PI;          // local copy to avoid repeated lookup
    const double* p   = x.data();     // raw pointer for faster access
    const size_t   n   = x.size();

    // Initial guess
    size_t  bestIdx = 0;
    double minDiff = std::fabs(p[0] - pi);

    // Main loop: unrolled by 4 for a bit of speed gain
    size_t i = 1;
    for (; i + 3 < n; i += 4) {
        double d0 = std::fabs(p[i]     - pi);
        if (d0 < minDiff) { minDiff = d0; bestIdx = i; }

        double d1 = std::fabs(p[i + 1] - pi);
        if (d1 < minDiff) { minDiff = d1; bestIdx = i + 1; }

        double d2 = std::fabs(p[i + 2] - pi);
        if (d2 < minDiff) { minDiff = d2; bestIdx = i + 2; }

        double d3 = std::fabs(p[i + 3] - pi);
        if (d3 < minDiff) { minDiff = d3; bestIdx = i + 3; }
    }

    // Tail loop for remaining elements
    for (; i < n; ++i) {
        double d = std::fabs(p[i] - pi);
        if (d < minDiff) { minDiff = d; bestIdx = i; }
    }

    return bestIdx;
}
