#include <thread>
#include <mutex>
#include <numeric>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
//  Optimised FFT helpers
// -----------------------------------------------------------------------------
static inline void bit_reversal(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    std::size_t m = 0;                         // number of bits
    std::size_t tmp = N;
    while (tmp >>= 1) ++m;                     // N is power of two

    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i)
    {
        if (rev > i)
            std::swap(x[i], x[rev]);

        std::size_t mask = N >> 1;
        while (rev & mask)
        {
            rev ^= mask;
            mask >>= 1;
        }
        rev ^= mask;                          // 1‐bit shift
    }
}

static inline void radix2_fft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    // Pre‑compute twiddle factors (W_N = e^{-2πi/N})
    std::vector<std::complex<double>> w(N >> 1);
    const double theta = -2.0 * M_PI / static_cast<double>(N);
    for (std::size_t i = 1; i < (N >> 1); ++i)
    {
        double t = theta * static_cast<double>(i);
        w[i] = std::complex<double>(std::cos(t), std::sin(t));
    }

    std::size_t step = 1;
    for (std::size_t len = N; len > 1; len >>= 1)
    {
        std::size_t half = len >> 1;
        double angle = -M_PI / static_cast<double>(half);
        std::complex<double> wlen(std::cos(angle), std::sin(angle));

        for (std::size_t i = 0; i < half; ++i)
            w[i] = std::pow(wlen, static_cast<double>(i));

        for (std::size_t i = 0; i < N; i += len)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::complex<double> u = x[i + j];
                std::complex<double> v = x[i + j + half] * w[j];
                x[i + j]           = u + v;
                x[i + j + half]    = u - v;
            }
        }
    }
}

inline void fft_helper(std::vector<std::complex<double>>& x)
{
    radix2_fft(x);
    bit_reversal(x);
}

// -----------------------------------------------------------------------------
//  Public API
// -----------------------------------------------------------------------------
/* Compute the inverse fourier transform of x in-place.
   The behaviour is identical to the reference implementation.
*/
inline void ifft(std::vector<std::complex<double>>& x)
{
    // 1. Conjugate
    for (auto& v : x) v = std::conj(v);
    // 2. Forward FFT
    fft_helper(x);
    // 3. Conjugate again
    for (auto& v : x) v = std::conj(v);
    // 4. Scale
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto& v : x) v *= invN;
}
