                sum += imageIn[(i_m1)*N + j_p1] * edgeKernel[0][2];

            // ( 0, -1)
            if (j_m1 >= 0)
                sum += imageIn[iN + j_m1] * edgeKernel[1][0];

            // ( 0,  0)
            sum += imageIn[iN + j] * edgeKernel[1][1];

            // ( 0, +1)
            if (j_p1 < static_cast<int>(N))
                sum += imageIn[iN + j_p1] * edgeKernel[1][2];

            // (+1, -1)
            if (i_p1 < static_cast<int>(N) && j_m1 >= 0)
                sum += imageIn[(i_p1)*N + j_m1] * edgeKernel[2][0];

            // (+1,  0)
            if (i_p1 < static_cast<int>(N))
                sum += imageIn[(i_p1)*N + j] * edgeKernel[2][1];

            // (+1, +1)
            if (i_p1 < static_cast<int>(N) && j_p1 < static_cast<int>(N))
                sum += imageIn[(i_p1)*N + j_p1] * edgeKernel[2][2];

            // Clamp result to [0,255]
            if (sum < 0)
                imageOut[iN + j] = 0;
            else if (sum > 255)
                imageOut[iN + j] = 255;
            else
                imageOut[iN + j] = sum;
        }
    }
