    // treat first row
    for (size_t j = 0; j < N; ++j) {
        int sum = input[j];
        if (j)          sum += input[j-1];
        if (j+1 < N)    sum += input[j+1];
        if (j)          sum += input[N + j-1];
        if (j+1 < N)    sum += input[N + j+1];
