    }

    // treat last row
    if (N > 1) {
        for (size_t j = 0; j < N; ++j) {
            int sum = input[(N-1)*N + j];
            if (j)          sum += input[(N-1)*N + j-1];
            if (j+1 < N)    sum += input[(N-1)*N + j+1];
            if (j)          sum += input[(N-2)*N + j-1];
