#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <numeric>
#include <omp.h>

// In‑place, radix‑2, Cooley‑Tukey FFT (decimation‑in‑time) that reproduces exactly the
// behaviour of the original code (including the final conjugation step).
// It is intentionally written for high performance on modern x86‑64 with
// GCC/Clang and 8‑thread OpenMP support.
//
// The outer loop over stages is parallelised (each stage works on independent
// sub‑bands).  Bit‑reversal is performed with a compact table generated once
// per call.  All arithmetic uses std::complex<double>, which GCC aggressively
// vectorises on the target architecture.
//
// Note: The function assumes that the input size N is a power of two.
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();

    // ---------- 1. Allocate temporary tables ----------
    // Twiddle factor table: for each stage s (log2(N) stages) we need
    // one complex twiddle per element in that stage.
    const std::size_t stages = static_cast<std::size_t>(std::log2(N));
    std::vector<std::complex<double>> twiddles(stages * (N / 2));

    // Bit‑reversal table
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t b = i;
        b = ((b & 0xaaaaaaaa) >> 1) | ((b & 0x55555555) << 1);
        b = ((b & 0xcccccccc) >> 2) | ((b & 0x33333333) << 2);
        b = ((b & 0xf0f0f0f0) >> 4) | ((b & 0x0f0f0f0f) << 4);
        b = ((b & 0xff00ff00) >> 8) | ((b & 0x00ff00ff) << 8);
        b = ((b >> 16) | (b << 16));
        rev[i] = b >> (32 - stages);
    }

    // ---------- 2. Compute twiddle factors ----------
    // For each stage s (1‑based), the twiddle exponent step is π / (N >> (s-1))
    for (std::size_t s = 1; s <= stages; ++s)
    {
        const std::size_t step   = N >> s;               // N / 2^s
        const std::size_t half   = step >> 1;           // N / 2^(s+1)
        const double   angleStep = -M_PI / static_cast<double>(half);
        std::complex<double> w(1.0, 0.0);

        for (std::size_t i = 0; i < half; ++i)
        {
            twiddles[(s - 1) * (N / 2) + i] = w;
            w *= std::exp(std::complex<double>(0.0, angleStep * static_cast<double>(i)));
        }
    }

    // ---------- 3. Main FFT loops ----------
    for (std::size_t s = 1; s <= stages; ++s)
    {
        const std::size_t half = N >> s;               // N / 2^s
        const std::size_t stride = half << 1;          // 2 * half
        const std::size_t stageIdx = (s - 1) * (N / 2);

        // Parallelise the outer loop over chunk of blocks; each iteration
        // works on a distinct chunk of data so there are no data races.
        #pragma omp parallel for schedule(static)
        for (std::size_t block = 0; block < N; block += stride)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                const std::size_t idx = block + j;
                const std::size_t idxTwin = idx + half;
                const std::complex<double> t = x[idxTwin] * twiddles[stageIdx + j];
                x[idxTwin] = x[idx] - t;
                x[idx]    += t;
            }
        }
    }

    // ---------- 4. Bit‑reversal ----------
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t j = rev[i];
        if (j > i)
            std::swap(x[i], x[j]);
    }

    // ---------- 5. Final conjugation ----------
    // Conjugation is element‑wise and independent; parallelise for speed.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
